VALUES
  ('dietitian-moex-09444', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '在鐵缺乏的發展過程中，以下那一項指標的變化是最靈敏的？', '["運鐵蛋白飽和度 (Transferrin saturation) 之下降", "血液血紅素濃度之下降", "血清儲鐵蛋白 (ferritin) 濃度之下降", "紅血球體積下降"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09445', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '血清白蛋白濃度常被用於評估個人蛋白質營養狀況，此一指標的缺點是：', '["易因發炎反應而使數值偏高", "靈敏度低，不易快速反映近期蛋白質營養狀況的改變", "數值因蛋白質攝取量增加而立即上升", "測量方法不一，無法在不同評估單位之間互相比較"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09446', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何種測量方法適合用來測量骨密度？', '["Air Displacement Plethysmography", "Bioelectrical Impedance", "Dual-Energy X-ray Absorptiometry", "Creatinine Excretion"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09447', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '以「相對劑量反應測驗」（relative dose-response test, RDR）評估維生素A之營養狀況時，下列敘述何者 正確？', '["表示給予一個劑量的維生素A後，血清維生素A濃度之增加幅度", "RDR的數值與體內的維生素A儲存量成正比", "RDR < 20 %代表受試者的維生素A營養狀況為“缺乏", "RDR > 50 %代表受試者的維生素A營養狀況為“良好"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09448', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '以下有關「平均細胞體積」（mean corpuscular volume, MCV）之敘述何者正確？', '["可由血球容積比（hematocrit）除以血紅素濃度得知", "健康男性之MCV數值高於健康女性", "若某位成年女性之MCV為70代表她有鐵缺乏的問題", "若某位成年女性之MCV為60代表她有葉酸缺乏的問題"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09449', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據行政院衛生署公布之「過重∕肥胖兒童與青少年之篩選及處理流程」，2-6 歲之學童若 BMI 超過該 年齡、性別過重BMI值，請問應進行何種處理方式？', '["立即執行體重控制計畫", "只要維持體重不再上升即可", "若身高低於25百分位值，則轉介小兒科醫師", "若無肥胖家族史，則需進行體重控制計畫"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09450', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '王小明為國小二年級學童，本學期開學時在校測量身高體重，發現他的BMI介於過重與肥胖之間，根據 行政院衛生署公布之「過重∕肥胖兒童與青少年之篩選及處理流程」，王小明若同時具有下列那一個條 件即應開始進行體重控制計畫？', '["血壓值過高", "血糖值過高", "肝功能異常", "白蛋白異常"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09451', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據國人膳食營養素參考攝取量之建議，我國懷孕第三期婦女鐵質之每日建議攝取量（Recommended Dietary Allowance, RDA）應為：', '["45 mg", "35 mg", "25 mg", "15 mg"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09452', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '王老太太因中風無法站立，請問營養師進行體位評估時，可使用下列何種營養評估方式估算王老太太的 身高？', '["膝高", "坐高", "單臂手長", "三頭肌皮下脂肪厚度"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09453', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據學校衛生法之規定，學校供應膳食者應提供衛生、安全及營養均衡之餐食，實施營養教育，並由營 養師督導及執行。高級中等以下學校，班級數在幾班以上者，應至少設置營養師一人？', '["10", "20", "30", "40"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
